SELECT category_name
FROM etf_categories
WHERE is_active = 1;

SELECT metric_name, metric_value, report_date
FROM etf_performance
WHERE metric_name = 'Total Expense' AND is_estimated = 0;

SELECT AVG(expense_value) AS average_expense
FROM etf_expenses
WHERE expense_type_id = 0;

SELECT category_id, COUNT(performance_id) AS performance_metric_count
FROM etf_performance
GROUP BY category_id;

SELECT MAX(metric_value) AS highest_total_expense
FROM etf_performance
WHERE metric_name = 'Total Expense';
